        long low = 0, high = maxTime;
        while (low < high) {
            long mid = (low + high) / 2;
            if (check(n, edges, mid, k)) {
                high = mid;
            } else {
                low = mid + 1;
            }
        }
        return low;
    }

    private static boolean check(long n, long[][] edges, long t, long k) {
        long[] parent = new long[(int) n];
        long[] rank = new long[(int) n];
        for (long i = 0; i < n; i++) {
            parent[(int) i] = (int) i;
            rank[(int) i] = 1;
        }

        java.util.function.Function<Long, Long> find = (u) -> {
            if (parent[(int) u] != (int) u) {
                parent[(int) u] = find((long) parent[(int) u]);
            }
            return parent[(int) u];
        };

        java.util.function.BiFunction<Long, Long, Boolean> union = (u, v) -> {
            long rootU = find.apply(u);
            long rootV = find.apply(v);
            if (rootU == rootV) return false;
            if (rank[(int) rootU] < rank[(int) rootV]) {
                parent[(int) rootU] = (int) rootV;
            } else {
                parent[(int) rootV] = (int) rootU;
                if (rank[(int) rootU] == rank[(int) rootV]) {
                    rank[(int) rootU]++;
                }
            }
            return true;
        };

        for (long[] e : edges) {
            if (e[2] > t) {
                long u = e[0];
                long v = e[1];
                union.apply(u, v);
            }
        }

        long components = 0;
        for (long i = 0; i < n; i++) {
            if (find.apply(i) == i) {
                components++;
            }
        }
        return components >= k;
    }
}
