public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));
        long maxTime = 0;
        for (long[] edge : edges) {
            maxTime = Math.max(maxTime, edge[2]);
        }
        long low = 0, high = maxTime;
        while (low < high) {
            long mid = (low + high) / 2;
            if (check(n, edges, mid, k)) {
                high = mid;
            } else {
                low = mid + 1;
            }
        }
        return low;
    }

    private static boolean check(long n, long[][] edges, long t, long k) {
        long[] parent = new long[(int) n];
        long[] rank = new long[(int) n];
        for (long i = 0; i < n; i++) {
            parent[i] = i;
            rank[i] = 1;
        }

        for (long[] edge : edges) {
            if (edge[2] > t) {
                long u = edge[0];
                long v = edge[1];
                long rootU = find(parent, u);
                long rootV = find(parent, v);
                if (rootU != rootV) {
                    if (rank[rootU] < rank[rootV]) {
                        parent[rootU] = rootV;
                    } else {
                        parent[rootV] = rootU;
                        if (rank[rootU] == rank[rootV]) {
                            rank[rootU]++;
                        }
                    }
                }
            }
        }

        long components = 0;
        for (long i = 0; i < n; i++) {
            if (find(parent, i) == i) {
                components++;
            }
        }
        return components >= k;
    }

    private static long find(long[] parent, long x) {
        long root = x;
        while (parent[root] != root) {
            root = parent[root];
        }
        while (x != root) {
            long next = parent[x];
            parent[x] = root;
            x = next;
        }
        return root;
    }
}
