import java.util.Arrays;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));
        long maxTime = 0;
        for (long[] e : edges) {
            if (e[2] > maxTime) {
                maxTime = e[2];
            }
        }
        long low = 0, high = maxTime;
        while (low < high) {
            long mid = (low + high) / 2;
            if (check(n, edges, mid, k)) {
                high = mid;
            } else {
                low = mid + 1;
            }
        }
        return low;
    }

    private static boolean check(long n, long[][] edges, long t, long k) {
        long[] parent = new long[(int) n];
        long[] rank = new long[(int) n];
        for (long i = 0; i < n; i++) {
            parent[(int) i] = (int) i;
            rank[(int) i] = 1;
        }
        for (long[] e : edges) {
            if (e[2] > t) {
                long u = (int) e[0];
                long v = (int) e[1];
                long rootU = find(parent, u);
                long rootV = find(parent, v);
                if (rootU != rootV) {
                    if (rank[(int) rootU] < rank[(int) rootV]) {
                        parent[(int) rootU] = (int) rootV;
                    } else {
                        parent[(int) rootV] = (int) rootU;
                        if (rank[(int) rootU] == rank[(int) rootV]) {
                            rank[(int) rootU]++;
                        }
                    }
                }
            }
        }
        long components = 0;
        for (long i = 0; i < n; i++) {
            if (find(parent, (int) i) == (int) i) {
                components++;
            }
        }
        return components >= k;
    }

    private static long find(long[] parent, long x) {
        while (parent[(int) x] != x) {
            parent[(int) x] = parent[(int) parent[(int) x]];
            x = parent[(int) x];
        }
        return x;
    }
}
